def create_sum(path):

    df = pd.DataFrame()
    for idx, i in enumerate(tqdm(Path(path).ls(), total=len(path.ls()))):
        name_ = get_m_name(Path(i).name)
        df.loc[idx, 'rec_name'] = name_
        df.loc[idx, 'fp'] = i
        df.loc[idx, 'fn'] = Path(i).name
        
    return (
        df.assign(
            pin_type=lambda df_: df_['rec_name'].map(get_pin_type()),
        )
    )

